files.css:
body { font-family: system-ui, sans-serif; padding: 1.5rem; max-width: 36rem; line-height: 1.6; }
code { background: #f1f5f9; padding: 0.1rem 0.35rem; border-radius: 4px; }
.note { color: #64748b; font-size: 0.95rem; }

body { font-family: system-ui, sans-serif; padding: 1.5rem; }
h1 { color: #2563eb; margin-top: 0; }
code { background: #e8f1fb; padding: 0.1rem 0.3rem; border-radius: 4px; }

body { font-family: system-ui, sans-serif; margin: 0; }
header { background: #2563eb; color: #fff; padding: 1.25rem 1.5rem; }
header h1 { margin: 0 0 0.25rem; font-size: 1.5rem; }
header p { margin: 0; opacity: 0.9; font-size: 0.95rem; }
p { padding: 1rem 1.5rem; }

body { font-family: system-ui, sans-serif; margin: 0; min-height: 12rem; display: flex; flex-direction: column; }
main { flex: 1; padding: 1.5rem; }
footer { background: #f1f5f9; padding: 1rem 1.5rem; color: #64748b; border-top: 1px solid #e2e8f0; }
footer p { margin: 0.25rem 0; }

body { font-family: system-ui, sans-serif; padding: 1rem; max-width: 36rem; }
section { background: #f8fafc; border: 1px solid #e2e8f0; border-radius: 8px; padding: 1rem 1.25rem; margin-bottom: 1rem; }
h2 { margin-top: 0; color: #2563eb; font-size: 1.1rem; }

body { font-family: system-ui, sans-serif; padding: 1rem; }
.box { padding: 1rem; margin-bottom: 0.75rem; border-radius: 8px; color: #fff; }
.box-a { background: #2563eb; }
.box-b { background: #7c3aed; }
.box-c { background: #059669; }

body { font-family: system-ui, sans-serif; padding: 1.5rem; max-width: 34rem; line-height: 1.6; }
.highlight { background: #fef08a; padding: 0.1rem 0.3rem; border-radius: 3px; }
code { color: #7c3aed; }

body { font-family: system-ui, sans-serif; margin: 0; }
header { background: #1e293b; color: #fff; padding: 1rem 1.25rem; }
header h1 { margin: 0 0 0.75rem; font-size: 1.25rem; }
nav a { color: #93c5fd; margin-right: 1rem; text-decoration: none; }
nav a:hover { text-decoration: underline; }
p { padding: 1rem 1.25rem; }

body { font-family: system-ui, sans-serif; padding: 1.5rem; max-width: 34rem; }
h2 { color: #2563eb; font-size: 1rem; margin-bottom: 0.5rem; }
ul, ol { line-height: 1.8; }

body { font-family: Georgia, serif; padding: 1.5rem; }
article { max-width: 32rem; border: 1px solid #e2e8f0; border-radius: 10px; padding: 1.25rem; background: #fff; box-shadow: 0 2px 8px rgba(0,0,0,0.06); }
h2 { margin-top: 0; color: #1e293b; }
small { color: #64748b; }

body { font-family: system-ui, sans-serif; padding: 1rem; }
.layout { display: flex; gap: 1rem; flex-wrap: wrap; max-width: 42rem; }
main { flex: 2; min-width: 200px; }
aside { flex: 1; min-width: 160px; background: #fffbeb; border: 1px solid #fde68a; border-radius: 8px; padding: 1rem; }
aside h3 { margin-top: 0; font-size: 0.95rem; color: #b45309; }

body { font-family: system-ui, sans-serif; padding: 1.5rem; max-width: 40rem; }
h2 { color: #2563eb; font-size: 1.1rem; }
code { background: #f1f5f9; padding: 0.1rem 0.3rem; border-radius: 4px; }
embed { display: block; margin-top: 0.75rem; border: 1px solid #cbd5e1; border-radius: 6px; }

body { font-family: system-ui, sans-serif; margin: 0; line-height: 1.5; }
header { background: #e8f1fb; padding: 1rem; border-bottom: 1px solid #dbeafe; }
header h1 { margin: 0 0 0.5rem; color: #2563eb; font-size: 1.25rem; }
nav a { color: #1e40af; margin-right: 0.35rem; }
.page { display: flex; gap: 1rem; padding: 1rem; flex-wrap: wrap; }
section { flex: 2; min-width: 220px; }
article { background: #fff; border: 1px solid #e2e8f0; border-radius: 8px; padding: 1rem; }
article h2 { margin-top: 0; font-size: 1.1rem; }
aside { flex: 1; min-width: 160px; background: #f0fdf4; border: 1px solid #bbf7d0; border-radius: 8px; padding: 1rem; }
aside h3 { margin-top: 0; font-size: 0.95rem; color: #166534; }
footer { background: #f1f5f9; padding: 0.75rem 1rem; color: #64748b; font-size: 0.9rem; }

starter.css:
body { font-family: system-ui, sans-serif; margin: 0; line-height: 1.5; }
header { background: #e8f1fb; padding: 1rem; }
nav a { margin-right: 1rem; }
section, aside { padding: 1rem; }
aside { background: #fffbeb; }
